import{c as a,Q as i,j as n,m as p}from"./chunks/framework.Bhbi9jCp.js";const o=JSON.parse('{"title":"HLS 与 DASH 点播","description":"","frontmatter":{},"headers":[],"relativePath":"mediaTechLearning/10-HLS与DASH点播.md","filePath":"mediaTechLearning/10-HLS与DASH点播.md","lastUpdated":1780887690000}'),e={name:"mediaTechLearning/10-HLS与DASH点播.md"};function t(l,s,h,d,k,r){return i(),n("div",null,[...s[0]||(s[0]=[p(`<h1 id="hls-与-dash-点播" tabindex="-1">HLS 与 DASH 点播 <a class="header-anchor" href="#hls-与-dash-点播" aria-label="Permalink to &quot;HLS 与 DASH 点播&quot;">​</a></h1><p>大视频不能直接给用户一个 MP4 让他从头下到尾。点播系统要分片、缓存、按网络切清晰度。</p><blockquote><p>一句话先记住:<strong>HLS / DASH = 清单文件 + 一堆媒体分片</strong>。播放器先拿清单,再按时间和清晰度拉分片。</p></blockquote><hr><h2 id="一、为什么不用单个-mp4" tabindex="-1">一、为什么不用单个 MP4 <a class="header-anchor" href="#一、为什么不用单个-mp4" aria-label="Permalink to &quot;一、为什么不用单个 MP4&quot;">​</a></h2><p>单 MP4 的问题:</p><ul><li>首屏慢</li><li>拖动依赖 Range 请求</li><li>清晰度切换难</li><li>CDN 缓存粒度粗</li><li>弱网下恢复差</li></ul><p>HLS / DASH 把视频切成小片:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>playlist.m3u8</span></span>
<span class="line"><span>  segment_000.ts</span></span>
<span class="line"><span>  segment_001.ts</span></span>
<span class="line"><span>  segment_002.ts</span></span></code></pre></div><p>播放器边播边拉下一片。</p><hr><h2 id="二、hls-基本结构" tabindex="-1">二、HLS 基本结构 <a class="header-anchor" href="#二、hls-基本结构" aria-label="Permalink to &quot;二、HLS 基本结构&quot;">​</a></h2><p>Master playlist:</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>#EXTM3U</span></span>
<span class="line"><span>#EXT-X-STREAM-INF:BANDWIDTH=1200000,RESOLUTION=1280x720</span></span>
<span class="line"><span>720p/index.m3u8</span></span>
<span class="line"><span>#EXT-X-STREAM-INF:BANDWIDTH=3000000,RESOLUTION=1920x1080</span></span>
<span class="line"><span>1080p/index.m3u8</span></span></code></pre></div><p>Media playlist:</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>#EXTM3U</span></span>
<span class="line"><span>#EXT-X-TARGETDURATION:6</span></span>
<span class="line"><span>#EXTINF:6.000,</span></span>
<span class="line"><span>seg_000.ts</span></span>
<span class="line"><span>#EXTINF:6.000,</span></span>
<span class="line"><span>seg_001.ts</span></span>
<span class="line"><span>#EXT-X-ENDLIST</span></span></code></pre></div><p>点播有 <code>#EXT-X-ENDLIST</code>,直播没有固定结尾。</p><hr><h2 id="三、dash-基本结构" tabindex="-1">三、DASH 基本结构 <a class="header-anchor" href="#三、dash-基本结构" aria-label="Permalink to &quot;三、DASH 基本结构&quot;">​</a></h2><p>DASH 用 MPD:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>manifest.mpd</span></span>
<span class="line"><span>  Representation 720p</span></span>
<span class="line"><span>  Representation 1080p</span></span>
<span class="line"><span>  audio</span></span>
<span class="line"><span>  segments</span></span></code></pre></div><p>HLS 在 Apple 生态和通用直播点播里很常见。DASH 在国际化 Web 点播、DRM、播放器生态里也常见。小团队先把 HLS 做稳。</p><hr><h2 id="四、生成单码率-hls" tabindex="-1">四、生成单码率 HLS <a class="header-anchor" href="#四、生成单码率-hls" aria-label="Permalink to &quot;四、生成单码率 HLS&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ffmpeg</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -i</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> input.mp4</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -c:v</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> libx264</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -c:a</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> aac</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -hls_time</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 6</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -hls_playlist_type</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> vod</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -hls_segment_filename</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;hls/seg_%03d.ts&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  hls/index.m3u8</span></span></code></pre></div><p>关键参数:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>hls_time              分片目标时长</span></span>
<span class="line"><span>hls_playlist_type vod 点播</span></span>
<span class="line"><span>hls_segment_filename  分片命名</span></span></code></pre></div><hr><h2 id="五、多码率-hls" tabindex="-1">五、多码率 HLS <a class="header-anchor" href="#五、多码率-hls" aria-label="Permalink to &quot;五、多码率 HLS&quot;">​</a></h2><p>先转多档:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ffmpeg</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -i</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> input.mp4</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -vf</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> scale=1280:-2</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -c:v</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> libx264</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -b:v</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 2500k</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -c:a</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> aac</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 720p.mp4</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ffmpeg</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -i</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> input.mp4</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -vf</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> scale=854:-2</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -c:v</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> libx264</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -b:v</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 1000k</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -c:a</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> aac</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 480p.mp4</span></span></code></pre></div><p>再分别切 HLS,最后写 master playlist。生产里通常由转码服务统一生成。</p><hr><h2 id="六、自适应码率-abr" tabindex="-1">六、自适应码率 ABR <a class="header-anchor" href="#六、自适应码率-abr" aria-label="Permalink to &quot;六、自适应码率 ABR&quot;">​</a></h2><p>播放器根据网络和缓冲选择清晰度:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>带宽好 -&gt; 拉 1080p</span></span>
<span class="line"><span>带宽差 -&gt; 降到 720p / 480p</span></span>
<span class="line"><span>缓冲低 -&gt; 降档保播放</span></span></code></pre></div><p>ABR 的目标不是永远最高清,而是<strong>少卡顿</strong>。用户对卡顿比对轻微降清晰度更敏感。</p><hr><h2 id="七、踩坑提醒" tabindex="-1">七、踩坑提醒 <a class="header-anchor" href="#七、踩坑提醒" aria-label="Permalink to &quot;七、踩坑提醒&quot;">​</a></h2><ol><li><strong>分片太长</strong>——首屏和切换慢。</li><li><strong>分片太短</strong>——请求数多,CDN 和播放器开销大。</li><li><strong>关键帧不对齐分片</strong>——切换和拖动容易出问题。</li><li><strong>只做单码率</strong>——弱网体验差。</li><li><strong>HLS 文件没配正确 MIME</strong>——播放器可能直接失败。</li></ol><p>下一篇:<code>11-M3U8、TS、fMP4 与分片.md</code>。</p>`,41)])])}const g=a(e,[["render",t]]);export{o as __pageData,g as default};
